import React, { useState, useEffect } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';



function Header() {
  const location = useLocation();
  const navigate = useNavigate();
  const isHome = location.pathname === '/';
  const [activeDropdown, setActiveDropdown] = useState(null);

  const toggleDropdown = (menu) => {
    setActiveDropdown(prev => prev === menu ? null : menu);
  };
  // close dropdown on route change
  useEffect(() => { setActiveDropdown(null); }, [location.pathname]);

  return (
    <header className = "main-header">
        <div className = "top-row">
          <Link 
          to="/" 
          className="title"
          style={{ cursor: isHome ? 'default' : 'pointer' }}
          onClick={() => setActiveDropdown(null)}
        >
          AURELIA
        </Link>
          <div className="search" role="button" aria-label="Search">
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
              <circle cx="11" cy="11" r="7"></circle>
              <line x1="21" y1="21" x2="16.65" y2="16.65"></line>
            </svg>
          </div>
          <div className="cart" role="button" aria-label="Cart">
            <svg xmlns="http://www.w3.org/2000/svg" width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
              <path d="M3 3h2l2.5 12.5a1 1 0 0 0 .98.75h9.04a1 1 0 0 0 .98-.78L21 7H6" />
              <circle cx="10" cy="19" r="1.2" />
              <circle cx="18" cy="19" r="1.2" />
            </svg>
          </div>
        </div>
        <div className="bottom-row">
          <a onClick={(e) => { console.log('Header click: WOMEN', e.target); console.log('top element at point:', document.elementFromPoint(e.clientX, e.clientY)); toggleDropdown('women'); }} 
             className={activeDropdown && activeDropdown !== 'women' ? 'hidden-nav' : ''}>
            WOMEN
          </a>
          <a onClick={(e) => { console.log('Header click: MEN', e.target); console.log('top element at point:', document.elementFromPoint(e.clientX, e.clientY)); toggleDropdown('men'); }} 
             className={activeDropdown && activeDropdown !== 'men' ? 'hidden-nav' : ''}>
            MEN
          </a>
          <a onClick={(e) => { console.log('Header click: EXCLUSIVE', e.target); console.log('top element at point:', document.elementFromPoint(e.clientX, e.clientY)); toggleDropdown('exclusive'); }} 
             className={activeDropdown && activeDropdown !== 'exclusive' ? 'hidden-nav' : ''}>
            EXCLUSIVE
          </a>
        </div>

        {activeDropdown && (
          <div className={`dropdown-content ${activeDropdown}`}>
            {activeDropdown === 'exclusive' ? (
              <>
                <a href="/exclusive/ethereal-summer" onClick={(e) => { e.preventDefault(); navigate('/exclusive/ethereal-summer'); }}>Ethereal Summer</a>
                <a href="/exclusive/bohemic-fall" onClick={(e) => { e.preventDefault(); navigate('/exclusive/bohemic-fall'); }}>Bohemic Fall</a>
              </>
            ) : (
              <>
                <a href={`/${activeDropdown}/fall`} onClick={(e) => { e.preventDefault(); navigate(`/${activeDropdown}/fall`); }}>Fall Collection '25</a>
                <a href={`/${activeDropdown}/spring`} onClick={(e) => { e.preventDefault(); navigate(`/${activeDropdown}/spring`); }}>Spring Collection '26</a>
                <a href={`/${activeDropdown}/summer`} onClick={(e) => { e.preventDefault(); navigate(`/${activeDropdown}/summer`); }}>Summer Collection '26</a>
              </>
            )}
            <div className="view-all-wrapper">
              <div className="view-all-line"></div>
              <a className="view-all-link" href={activeDropdown === 'exclusive' ? '/exclusive' : `/${activeDropdown}`} onClick={(e) => { e.preventDefault(); navigate(activeDropdown === 'exclusive' ? '/exclusive' : `/${activeDropdown}`); }}>VIEW ALL</a>
            </div>
          </div>
        )}
    </header>
  );
}

export default Header;
